const sales       = items[0].json;
const repairs     = items[1].json;
// Collect all top-product rows (may be up to 5 items from the query)
const topProducts = items.slice(2, items.length - 1).map(i => i.json);
const battery     = items[items.length - 1].json;

const today = new Date().toLocaleDateString('en-LK', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

const topProductLines = topProducts.length > 0
  ? topProducts.map((p,i) => `${i+1}. ${p.name} — ${p.units_sold} units — LKR ${Number(p.revenue).toLocaleString()}`).join('\n')
  : 'No sales recorded';

return [{
  json: {
    // Fields for the daily_pulse.html PDF template
    date: today,
    branch: 'Main Branch',
    generated_by: 'n8n automation',
    total_sales: Number(sales.total_revenue) || 0,
    total_transactions: Number(sales.total_orders) || 0,
    total_repairs_completed: Number(repairs.completed) || 0,
    battery_alerts: Number(battery.critical_alerts) || 0,
    top_products: topProducts.map(p => ({ name: p.name, qty: Number(p.units_sold) || 0, revenue: Number(p.revenue) || 0 })),
    // For Telegram message
    reportText: [
      `📊 *TechMo Daily Pulse — ${today}*`,
      '',
      '💰 *Sales*',
      `  Orders: *${sales.total_orders}*  |  Revenue: *LKR ${Number(sales.total_revenue).toLocaleString()}*`,
      `  Customers: ${sales.unique_customers}  |  Voided: ${sales.voided_orders}`,
      '',
      '🔧 *Repairs*',
      `  New today: ${repairs.new_today}  |  Completed: ${repairs.completed}`,
      `  Ready for pickup: ${repairs.ready_pickup}  |  In progress: ${repairs.in_progress}`,
      `  Awaiting parts: ${repairs.awaiting_parts}`,
      '',
      '🏆 *Top 5 Products*',
      topProductLines,
      battery.critical_alerts > 0 ? `\n🔋 *Battery Alerts:* ${battery.critical_alerts} critical` : '',
      '',
      '_Automated report by TechMo n8n_'
    ].filter(Boolean).join('\n')
  }
}];
